/**
 * Cross-platform XLSX pack/unpack and cell helpers.
 * Uses system zip/unzip (macOS/Linux) or PowerShell (Windows).
 */

const fs = require("fs");
const path = require("path");
const os = require("os");
const { execSync } = require("child_process");

function xmlEscape(s) {
  return String(s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

/**
 * Set or replace a cell value in sheet XML, preserving style when present.
 */
function setCellValue(sheetXml, ref, value, { asString = false } = {}) {
  const cellRe = new RegExp(`<c r="${ref}"([^>/]*)(?:/>|>([\\s\\S]*?)</c>)`);
  const m = sheetXml.match(cellRe);

  if (value === null || value === undefined || value === "") {
    if (!m) return sheetXml;
    let attrs = m[1] || "";
    attrs = attrs.replace(/\s*t="[^"]*"/g, "");
    return sheetXml.replace(cellRe, `<c r="${ref}"${attrs}/>`);
  }

  const writeAsString = asString || typeof value === "string";

  if (m) {
    let attrs = m[1] || "";
    attrs = attrs.replace(/\s*t="[^"]*"/g, "");
    if (writeAsString) {
      return sheetXml.replace(
        cellRe,
        `<c r="${ref}"${attrs} t="inlineStr"><is><t>${xmlEscape(
          String(value)
        )}</t></is></c>`
      );
    }
    return sheetXml.replace(
      cellRe,
      `<c r="${ref}"${attrs}><v>${value}</v></c>`
    );
  }

  const rowNum = ref.replace(/^[A-Z]+/, "");
  const rowRe = new RegExp(`(<row r="${rowNum}"[^>]*>)([\\s\\S]*?)(</row>)`);
  if (!sheetXml.match(rowRe)) {
    throw new Error(`Row ${rowNum} not found for cell ${ref}`);
  }
  const newCell = writeAsString
    ? `<c r="${ref}" t="inlineStr"><is><t>${xmlEscape(
        String(value)
      )}</t></is></c>`
    : `<c r="${ref}"><v>${value}</v></c>`;
  return sheetXml.replace(rowRe, `$1$2${newCell}$3`);
}

function hasCmd(cmd) {
  try {
    execSync(
      process.platform === "win32" ? `where ${cmd}` : `command -v ${cmd}`,
      { stdio: "pipe" }
    );
    return true;
  } catch {
    return false;
  }
}

/**
 * Unpack an xlsx (zip) into a directory.
 */
function unpackXlsx(xlsxPath, destDir) {
  fs.mkdirSync(destDir, { recursive: true });
  const absXlsx = path.resolve(xlsxPath);
  const absDest = path.resolve(destDir);

  if (process.platform === "win32" && !hasCmd("unzip")) {
    execSync(
      `powershell -NoProfile -Command "Expand-Archive -LiteralPath '${absXlsx.replace(
        /'/g,
        "''"
      )}' -DestinationPath '${absDest.replace(/'/g, "''")}' -Force"`,
      { stdio: "pipe" }
    );
    return;
  }

  execSync(`unzip -q -o "${absXlsx}" -d "${absDest}"`, { stdio: "pipe" });
}

/**
 * Pack a directory into an xlsx (zip) file.
 */
function packXlsx(sourceDir, outputPath) {
  const absSrc = path.resolve(sourceDir);
  const absOut = path.resolve(outputPath);
  fs.mkdirSync(path.dirname(absOut), { recursive: true });
  if (fs.existsSync(absOut)) fs.unlinkSync(absOut);

  if (process.platform === "win32" && !hasCmd("zip")) {
    const ps1 = path.join(os.tmpdir(), `zip_xlsx_${Date.now()}.ps1`);
    fs.writeFileSync(
      ps1,
      [
        "Add-Type -AssemblyName System.IO.Compression.FileSystem",
        `if (Test-Path -LiteralPath '${absOut.replace(/'/g, "''")}') { Remove-Item -LiteralPath '${absOut.replace(/'/g, "''")}' -Force }`,
        `[System.IO.Compression.ZipFile]::CreateFromDirectory('${absSrc.replace(/'/g, "''")}', '${absOut.replace(/'/g, "''")}', [System.IO.Compression.CompressionLevel]::Optimal, $false)`,
      ].join("\r\n")
    );
    try {
      execSync(`powershell -NoProfile -ExecutionPolicy Bypass -File "${ps1}"`, {
        stdio: "pipe",
      });
    } finally {
      try {
        fs.unlinkSync(ps1);
      } catch {
        /* ignore */
      }
    }
    return;
  }

  // zip contents of directory (not the directory itself)
  execSync(`cd "${absSrc}" && zip -qr "${absOut}" .`, { stdio: "pipe" });
}

/**
 * Copy template xlsx, yield unpacked dir, pack to output when done.
 * @returns {{ unpacked: string, tmp: string, finish: (outputPath: string) => void, cleanup: () => void }}
 */
function openTemplateCopy(templatePath) {
  const tmp = fs.mkdtempSync(path.join(os.tmpdir(), "ferc-xlsx-"));
  const zipCopy = path.join(tmp, "book.xlsx");
  const unpacked = path.join(tmp, "out");
  fs.copyFileSync(templatePath, zipCopy);
  unpackXlsx(zipCopy, unpacked);

  return {
    tmp,
    unpacked,
    finish(outputPath) {
      packXlsx(unpacked, outputPath);
    },
    cleanup() {
      fs.rmSync(tmp, { recursive: true, force: true });
    },
  };
}

/**
 * Optionally rename the first sheet in workbook.xml.
 */
function setSheetName(unpackedDir, sheetName) {
  if (!sheetName) return;
  const wbPath = path.join(unpackedDir, "xl", "workbook.xml");
  let wb = fs.readFileSync(wbPath, "utf8");
  if (!wb.includes(`name="${sheetName}"`)) {
    wb = wb.replace(
      /(<sheet\s+name=")[^"]+(")/,
      `$1${sheetName.replace(/"/g, "")}$2`
    );
    fs.writeFileSync(wbPath, wb, "utf8");
  }
}

module.exports = {
  xmlEscape,
  setCellValue,
  unpackXlsx,
  packXlsx,
  openTemplateCopy,
  setSheetName,
};

/**
 * Fill about.xlsx from a FERC Form 1 XBRL (.xbrl / .xml) filing.
 *
 * Usage:
 *   node fill_about_info_xbrl.js [xbrl] [template] [outputName]
 */

const fs = require("fs");
const path = require("path");
const {
  loadXbrl,
  getStringFact,
  detectXbrlMeta,
  detectCompanyFromXbrl,
} = require("./xbrl_common");
const {
  companyFolderName,
  resolveCompanyDir,
  resolveTemplatePath,
} = require("./lib/company");
const { openTemplateCopy, setCellValue, setSheetName } = require("./lib/xlsx_utils");

function parseAboutFromXbrl(doc) {
  const pref = [];
  if (doc.primaryDuration) pref.push(doc.primaryDuration.id);

  const meta = detectXbrlMeta(doc);
  const address =
    getStringFact(doc, "AddressOfPrincipalOfficeAtEndOfPeriod", pref) ||
    getStringFact(doc, "PrincipalBusinessAddress", pref) ||
    "";
  const name_of_contact = getStringFact(doc, "NameOfContactPerson", pref) || "";
  const title_of_contact = getStringFact(doc, "TitleOfContactPerson", pref) || "";
  const address_of_contact =
    getStringFact(doc, "AddressOfContactPerson", pref) || address || "";
  const telephone_of_contact =
    getStringFact(doc, "TelephoneOfContactPerson", pref) ||
    getStringFact(doc, "TelephoneNumber", pref) ||
    "";
  const date_of_report =
    getStringFact(doc, "ReportDate", pref) ||
    getStringFact(doc, "AttestationDate", pref) ||
    getStringFact(doc, "DocumentDate", pref) ||
    "";

  return {
    utility_id: meta.utilityId || "",
    report_year: meta.reportYear,
    address,
    name_of_contact,
    title_of_contact,
    address_of_contact,
    telephone_of_contact,
    date_of_report,
  };
}

function fillAboutFromXbrl({
  xbrlPath,
  templatePath,
  baseDir,
  outputFileName,
  companyName,
  sheetName = "about",
}) {
  if (!fs.existsSync(xbrlPath)) throw new Error(`XBRL not found: ${xbrlPath}`);
  if (!fs.existsSync(templatePath))
    throw new Error(`Template not found: ${templatePath}`);

  const doc = loadXbrl(xbrlPath);
  const about = parseAboutFromXbrl(doc);
  if (about.report_year == null) {
    throw new Error("Could not determine report_year from XBRL");
  }

  const meta = detectXbrlMeta(doc, xbrlPath);
  const companyShort =
    companyName ||
    detectCompanyFromXbrl(doc, xbrlPath) ||
    companyFolderName(meta.respondent, "", xbrlPath);
  const root = baseDir || path.dirname(path.resolve(templatePath));
  const { companyDir, company, created: companyFolderCreated } =
    resolveCompanyDir(root, companyShort);

  const fileName =
    outputFileName ||
    `about_${about.utility_id || "UNKNOWN"}_${about.report_year}.xlsx`;
  const finalPath = path.join(companyDir, path.basename(fileName));

  const pack = openTemplateCopy(templatePath);
  try {
    const sheetPath = path.join(pack.unpacked, "xl", "worksheets", "sheet1.xml");
    let sheet = fs.readFileSync(sheetPath, "utf8");
    const fills = [
      { ref: "B1", value: about.utility_id, asString: true },
      { ref: "B2", value: about.report_year, asString: false },
      { ref: "B3", value: about.address, asString: true },
      { ref: "B4", value: about.name_of_contact, asString: true },
      { ref: "B5", value: about.title_of_contact, asString: true },
      { ref: "B6", value: about.address_of_contact, asString: true },
      { ref: "B7", value: about.telephone_of_contact, asString: true },
      { ref: "B8", value: about.date_of_report, asString: true },
    ];
    for (const f of fills) {
      sheet = setCellValue(sheet, f.ref, f.value, { asString: f.asString });
    }
    fs.writeFileSync(sheetPath, sheet, "utf8");
    setSheetName(pack.unpacked, sheetName);
    pack.finish(finalPath);
  } finally {
    pack.cleanup();
  }

  return {
    outputPath: finalPath,
    companyDir,
    company,
    companyFolderCreated,
    respondent: meta.respondent,
    about,
  };
}

function main() {
  const dir = __dirname;
  const xbrlPath = path.resolve(
    dir,
    process.argv[2] || "filings/ClecoPowerLlc2020.xbrl"
  );
  const templatePath = resolveTemplatePath(dir, process.argv[3] || "about.xlsx");
  const outputArg = process.argv[4] || null;

  const result = fillAboutFromXbrl({
    xbrlPath,
    templatePath,
    baseDir: dir,
    outputFileName: outputArg ? path.basename(outputArg) : undefined,
  });

  console.log(
    "Company:",
    result.company,
    `(${result.respondent || "n/a"})`,
    result.companyFolderCreated ? "[folder created]" : "[existing folder]"
  );
  console.log("Folder:", result.companyDir);
  console.log("Wrote:", result.outputPath);
  for (const [k, v] of Object.entries(result.about)) {
    console.log(`  ${k}: ${v}`);
  }
}

if (require.main === module) {
  try {
    main();
  } catch (e) {
    console.error(e.message || e);
    process.exit(1);
  }
}

module.exports = { parseAboutFromXbrl, fillAboutFromXbrl };

/**
 * Fill om_expenses.xlsx from a FERC Form 1 XBRL filing.
 *
 * Maps template line_no → concept via lib/om_xbrl_map.js.
 * Current year = primary duration; previous year = prior duration.
 *
 * Usage:
 *   node fill_om_expenses_xbrl.js [xbrl] [template] [outputName]
 */

const fs = require("fs");
const path = require("path");
const {
  loadXbrl,
  getNumericFact,
  detectXbrlMeta,
  detectCompanyFromXbrl,
} = require("./xbrl_common");
const { resolveCompanyDir, resolveTemplatePath } = require("./lib/company");
const { openTemplateCopy, setCellValue, setSheetName } = require("./lib/xlsx_utils");
const { OM_LINE_CONCEPTS } = require("./lib/om_xbrl_map");

function lineKey(raw) {
  const t = String(raw || "").trim();
  if (!t) return "";
  if (!/^\d+(\.\d+)?$/.test(t)) return t;
  const n = Number(t);
  if (!Number.isFinite(n)) return t;
  if (Math.abs(n - Math.round(n)) < 1e-9) return String(Math.round(n));
  const one = Math.round(n * 10) / 10;
  if (Math.abs(n - one) < 1e-6) {
    const s = one.toFixed(1);
    return s.endsWith(".0") ? String(Math.round(one)) : s;
  }
  return String(n);
}

function parseOmExpensesFromXbrl(doc) {
  const curCtx = doc.primaryDuration ? doc.primaryDuration.id : null;
  const prevCtx = doc.priorDuration ? doc.priorDuration.id : null;
  const byLine = new Map();

  for (const [line, concept] of Object.entries(OM_LINE_CONCEPTS)) {
    const amount_for_current_year = getNumericFact(doc, concept, curCtx);
    const amount_for_previous_year = getNumericFact(doc, concept, prevCtx);
    if (
      amount_for_current_year != null ||
      amount_for_previous_year != null
    ) {
      byLine.set(line, {
        line_no: line,
        account: concept,
        amount_for_current_year,
        amount_for_previous_year,
      });
    }
  }
  return byLine;
}

function readTemplateLineRows(sheetXml) {
  const rows = [];
  const rowRe = /<row r="(\d+)"[^>]*>([\s\S]*?)<\/row>/g;
  let m;
  while ((m = rowRe.exec(sheetXml))) {
    const r = Number(m[1]);
    if (r < 4) continue;
    const cellA = m[2].match(
      /<c r="A\d+"([^>]*)(?:\/>|>([\s\S]*?)<\/c>)/
    );
    if (!cellA) continue;
    let val = null;
    const body = cellA[2] || "";
    const v = body.match(/<v>([^<]*)<\/v>/);
    const t = body.match(/<t[^>]*>([^<]*)<\/t>/);
    if (t) val = t[1];
    else if (v) val = v[1];
    if (val == null || val === "") continue;
    const key = lineKey(val);
    if (key) rows.push({ excelRow: r, line_no: key });
  }
  return rows;
}

function fillOmExpensesFromXbrl({
  xbrlPath,
  templatePath,
  baseDir,
  outputFileName,
  utilityId,
  reportYear,
  companyName,
  sheetName = "om_expenses",
}) {
  if (!fs.existsSync(xbrlPath)) throw new Error(`XBRL not found: ${xbrlPath}`);
  if (!fs.existsSync(templatePath))
    throw new Error(`Template not found: ${templatePath}`);

  const doc = loadXbrl(xbrlPath);
  const meta = detectXbrlMeta(doc, xbrlPath);
  const resolvedUtilityId = utilityId || meta.utilityId || "UNKNOWN";
  const resolvedYear =
    reportYear != null ? Number(reportYear) : meta.reportYear;
  if (resolvedYear == null || Number.isNaN(resolvedYear)) {
    throw new Error("Could not determine report_year from XBRL");
  }

  const companyShort =
    companyName || detectCompanyFromXbrl(doc, xbrlPath);
  const byLine = parseOmExpensesFromXbrl(doc);
  if (!byLine.size) {
    throw new Error("No O&M expense facts matched in XBRL");
  }

  const root = baseDir || path.dirname(path.resolve(templatePath));
  const { companyDir, company, created: companyFolderCreated } =
    resolveCompanyDir(root, companyShort);

  const fileName =
    outputFileName ||
    `om_expenses_${resolvedUtilityId}_${resolvedYear}.xlsx`;
  const finalPath = path.join(companyDir, path.basename(fileName));

  const pack = openTemplateCopy(templatePath);
  let filled = 0;
  try {
    const sheetPath = path.join(pack.unpacked, "xl", "worksheets", "sheet1.xml");
    let sheet = fs.readFileSync(sheetPath, "utf8");
    sheet = setCellValue(sheet, "B1", resolvedUtilityId, { asString: true });
    sheet = setCellValue(sheet, "B2", resolvedYear);

    const templateRows = readTemplateLineRows(sheet);
    for (const tr of templateRows) {
      const data = byLine.get(tr.line_no);
      if (!data) continue;
      sheet = setCellValue(
        sheet,
        `C${tr.excelRow}`,
        data.amount_for_current_year
      );
      sheet = setCellValue(
        sheet,
        `D${tr.excelRow}`,
        data.amount_for_previous_year
      );
      filled++;
    }

    fs.writeFileSync(sheetPath, sheet, "utf8");
    setSheetName(pack.unpacked, sheetName);
    pack.finish(finalPath);
  } finally {
    pack.cleanup();
  }

  return {
    outputPath: finalPath,
    companyDir,
    company,
    companyFolderCreated,
    respondent: meta.respondent,
    utilityId: resolvedUtilityId,
    reportYear: resolvedYear,
    filled,
    matchedConcepts: byLine.size,
  };
}

function main() {
  const dir = __dirname;
  const xbrlPath = path.resolve(
    dir,
    process.argv[2] || "filings/ClecoPowerLlc2020.xbrl"
  );
  const templatePath = resolveTemplatePath(
    dir,
    process.argv[3] || "om_expenses.xlsx"
  );
  const result = fillOmExpensesFromXbrl({
    xbrlPath,
    templatePath,
    baseDir: dir,
    outputFileName: process.argv[4]
      ? path.basename(process.argv[4])
      : undefined,
  });
  console.log("Company:", result.company);
  console.log("Wrote:", result.outputPath);
  console.log(
    `Filled ${result.filled} template rows from ${result.matchedConcepts} concepts`
  );
}

if (require.main === module) {
  try {
    main();
  } catch (e) {
    console.error(e.message || e);
    process.exit(1);
  }
}

module.exports = {
  parseOmExpensesFromXbrl,
  fillOmExpensesFromXbrl,
};

/**
 * Fill plant_in_service.xlsx from a FERC Form 1 XBRL filing.
 *
 * Maps template line_no → concept via lib/plant_xbrl_map.js.
 * BoY/EoY use instant contexts; flow columns use primary duration.
 *
 * Usage:
 *   node fill_plant_in_service_xbrl.js [xbrl] [template] [outputName]
 */

const fs = require("fs");
const path = require("path");
const {
  loadXbrl,
  getNumericFact,
  detectXbrlMeta,
  detectCompanyFromXbrl,
} = require("./xbrl_common");
const { resolveCompanyDir, resolveTemplatePath } = require("./lib/company");
const { openTemplateCopy, setCellValue, setSheetName } = require("./lib/xlsx_utils");
const { PLANT_LINE_CONCEPTS } = require("./lib/plant_xbrl_map");

const VALIDATION_TOLERANCE = 1;

function lineKey(raw) {
  const t = String(raw || "").trim();
  if (!t) return "";
  if (/^\d+(\.\d+)?$/.test(t)) {
    const n = Number(t);
    if (!Number.isFinite(n)) return t;
    if (Math.abs(n - Math.round(n)) < 1e-9) return String(Math.round(n));
    const one = Math.round(n * 10) / 10;
    if (Math.abs(n - one) < 1e-6) {
      const s = one.toFixed(1);
      return s.endsWith(".0") ? String(Math.round(one)) : s;
    }
    return String(n);
  }
  return t;
}

function plantMetricsForConcept(doc, concept) {
  const boyCtx = doc.boyInstant ? doc.boyInstant.id : null;
  const eoyCtx = doc.eoyInstant ? doc.eoyInstant.id : null;
  const flowCtx = doc.primaryDuration ? doc.primaryDuration.id : null;

  const balance_BoY = getNumericFact(doc, concept, boyCtx);
  const balance_EoY = getNumericFact(doc, concept, eoyCtx);
  const additions = getNumericFact(doc, `${concept}Additions`, flowCtx);
  const retirements = getNumericFact(doc, `${concept}Retirements`, flowCtx);
  const adjustments = getNumericFact(doc, `${concept}Adjustments`, flowCtx);
  const transfers = getNumericFact(doc, `${concept}Transfers`, flowCtx);

  return {
    balance_BoY,
    additions,
    retirements,
    adjustments,
    transfers,
    balance_EoY,
  };
}

function parsePlantInServiceFromXbrl(doc) {
  const byLine = new Map();
  for (const [line, concept] of Object.entries(PLANT_LINE_CONCEPTS)) {
    const m = plantMetricsForConcept(doc, concept);
    // Keep row if any metric present
    if (
      m.balance_BoY != null ||
      m.balance_EoY != null ||
      m.additions != null ||
      m.retirements != null ||
      m.adjustments != null ||
      m.transfers != null
    ) {
      byLine.set(line, { line_no: line, account: concept, ...m });
    }
  }
  return byLine;
}

/**
 * Read template line numbers from column A (rows 4+).
 */
function readTemplateLineRows(sheetXml) {
  const rows = [];
  const rowRe = /<row r="(\d+)"[^>]*>([\s\S]*?)<\/row>/g;
  let m;
  while ((m = rowRe.exec(sheetXml))) {
    const r = Number(m[1]);
    if (r < 4) continue;
    const cellA = m[2].match(
      /<c r="A\d+"([^>]*)(?:\/>|>([\s\S]*?)<\/c>)/
    );
    if (!cellA) continue;
    let val = null;
    const body = cellA[2] || "";
    const v = body.match(/<v>([^<]*)<\/v>/);
    const t = body.match(/<t[^>]*>([^<]*)<\/t>/);
    if (t) val = t[1];
    else if (v) val = v[1];
    if (val == null || val === "") continue;
    const key = lineKey(val);
    if (key) rows.push({ excelRow: r, line_no: key });
  }
  return rows;
}

function fillPlantInServiceFromXbrl({
  xbrlPath,
  templatePath,
  baseDir,
  outputFileName,
  utilityId,
  reportYear,
  companyName,
  sheetName = "plant_in_service",
}) {
  if (!fs.existsSync(xbrlPath)) throw new Error(`XBRL not found: ${xbrlPath}`);
  if (!fs.existsSync(templatePath))
    throw new Error(`Template not found: ${templatePath}`);

  const doc = loadXbrl(xbrlPath);
  const meta = detectXbrlMeta(doc, xbrlPath);
  const resolvedUtilityId = utilityId || meta.utilityId || "UNKNOWN";
  const resolvedYear =
    reportYear != null ? Number(reportYear) : meta.reportYear;
  if (resolvedYear == null || Number.isNaN(resolvedYear)) {
    throw new Error("Could not determine report_year from XBRL");
  }

  const companyShort =
    companyName || detectCompanyFromXbrl(doc, xbrlPath);
  const byLine = parsePlantInServiceFromXbrl(doc);
  if (!byLine.size) {
    throw new Error("No Electric Plant In Service facts matched in XBRL");
  }

  const root = baseDir || path.dirname(path.resolve(templatePath));
  const { companyDir, company, created: companyFolderCreated } =
    resolveCompanyDir(root, companyShort);

  const fileName =
    outputFileName ||
    `plant_in_service_${resolvedUtilityId}_${resolvedYear}.xlsx`;
  const finalPath = path.join(companyDir, path.basename(fileName));

  const pack = openTemplateCopy(templatePath);
  let filled = 0;
  const validationWarnings = [];
  try {
    const sheetPath = path.join(pack.unpacked, "xl", "worksheets", "sheet1.xml");
    let sheet = fs.readFileSync(sheetPath, "utf8");
    sheet = setCellValue(sheet, "B1", resolvedUtilityId, { asString: true });
    sheet = setCellValue(sheet, "B2", resolvedYear);

    const templateRows = readTemplateLineRows(sheet);
    for (const tr of templateRows) {
      const data = byLine.get(tr.line_no);
      if (!data) continue;
      const cols = [
        ["C", data.balance_BoY],
        ["D", data.additions],
        ["E", data.retirements],
        ["F", data.adjustments],
        ["G", data.transfers],
        ["H", data.balance_EoY],
      ];
      for (const [col, val] of cols) {
        sheet = setCellValue(sheet, `${col}${tr.excelRow}`, val);
      }
      filled++;

      if (
        data.balance_BoY != null &&
        data.balance_EoY != null &&
        (data.additions != null ||
          data.retirements != null ||
          data.adjustments != null ||
          data.transfers != null)
      ) {
        const expected =
          data.balance_BoY +
          (data.additions || 0) -
          (data.retirements || 0) +
          (data.adjustments || 0) +
          (data.transfers || 0);
        if (Math.abs(expected - data.balance_EoY) > VALIDATION_TOLERANCE) {
          validationWarnings.push({
            line_no: tr.line_no,
            expected,
            balance_EoY: data.balance_EoY,
          });
        }
      }
    }

    fs.writeFileSync(sheetPath, sheet, "utf8");
    setSheetName(pack.unpacked, sheetName);
    pack.finish(finalPath);
  } finally {
    pack.cleanup();
  }

  return {
    outputPath: finalPath,
    companyDir,
    company,
    companyFolderCreated,
    respondent: meta.respondent,
    utilityId: resolvedUtilityId,
    reportYear: resolvedYear,
    filled,
    matchedConcepts: byLine.size,
    validationWarnings,
  };
}

function main() {
  const dir = __dirname;
  const xbrlPath = path.resolve(
    dir,
    process.argv[2] || "filings/ClecoPowerLlc2020.xbrl"
  );
  const templatePath = resolveTemplatePath(
    dir,
    process.argv[3] || "plant_in_service.xlsx"
  );
  const result = fillPlantInServiceFromXbrl({
    xbrlPath,
    templatePath,
    baseDir: dir,
    outputFileName: process.argv[4]
      ? path.basename(process.argv[4])
      : undefined,
  });
  console.log("Company:", result.company);
  console.log("Wrote:", result.outputPath);
  console.log(
    `Filled ${result.filled} template rows from ${result.matchedConcepts} concepts`
  );
  if (result.validationWarnings.length) {
    console.log("Validation warnings:", result.validationWarnings.length);
  }
}

if (require.main === module) {
  try {
    main();
  } catch (e) {
    console.error(e.message || e);
    process.exit(1);
  }
}

module.exports = {
  parsePlantInServiceFromXbrl,
  fillPlantInServiceFromXbrl,
};
